        _ => {
            eprintln!("Unknown command: {}", command);
            process::exit(1);
        }
    }
}

fn init() {
    if Path::new(MINIGIT_DIR).exists() {
        eprintln!("minigit repository already exists");
        process::exit(1);
    }

    fs::create_dir(MINIGIT_DIR).unwrap();
    fs::create_dir(format!("{}/objects", MINIGIT_DIR)).unwrap();
    fs::create_dir(format!("{}/refs", MINIGIT_DIR)).unwrap();
    fs::create_dir(format!("{}/refs/heads", MINIGIT_DIR)).unwrap();

    let mut index = File::create(INDEX_FILE).unwrap();
    let mut head = File::create(HEAD_FILE).unwrap();
    head.write_all(b"ref: refs/heads/main\n").unwrap();

    println!("Initialized empty minigit repository");
}

fn add(path: &str) {
    if !Path::new(MINIGIT_DIR).exists() {
        eprintln!("not a minigit repository");
        process::exit(1);
    }

    if !Path::new(path).exists() {
        eprintln!("file not found: {}", path);
        process::exit(1);
    }

    let hash = hash_object(path);
    let mut index = HashMap::new();

    if Path::new(INDEX_FILE).exists() {
        let file = File::open(INDEX_FILE).unwrap();
        let reader = BufReader::new(file);
        for line in reader.lines() {
            let line = line.unwrap();
            let parts: Vec<&str> = line.split_whitespace().collect();
            if parts.len() == 2 {
                index.insert(parts[1].to_string(), parts[0].to_string());
            }
        }
    }

    index.insert(path.to_string(), hash.clone());

    let file = OpenOptions::new()
        .write(true)
        .create(true)
        .truncate(true)
        .open(INDEX_FILE)
        .unwrap();
    let mut writer = BufWriter::new(file);
    for (path, hash) in index {
        writeln!(writer, "{} {}", hash, path).unwrap();
    }
}

fn hash_object(path: &str) -> String {
    let mut file = File::open(path).unwrap();
    let mut contents = Vec::new();
    file.read_to_end(&mut contents).unwrap();

    let blob = format!("blob {}\0{}", contents.len(), String::from_utf8_lossy(&contents));
    let hash = format!("{:x}", md5::compute(&blob));

    let dir = &hash[..2];
    let file_name = &hash[2..];
    let object_dir = format!("{}/objects/{}", MINIGIT_DIR, dir);
    fs::create_dir_all(&object_dir).unwrap();

    let object_path = format!("{}/{}", object_dir, file_name);
    let mut object_file = File::create(object_path).unwrap();
    object_file.write_all(&blob.into_bytes()).unwrap();

    hash
}

fn cat_file(hash: &str) {
    let dir = &hash[..2];
    let file_name = &hash[2..];
    let object_path = format!("{}/objects/{}/{}", MINIGIT_DIR, dir, file_name);

    if !Path::new(&object_path).exists() {
        eprintln!("object not found");
        process::exit(1);
    }

    let mut file = File::open(&object_path).unwrap();
    let mut contents = Vec::new();
    file.read_to_end(&mut contents).unwrap();

    let blob = String::from_utf8(contents).unwrap();
    let parts: Vec<&str> = blob.splitn(3, '\0').collect();
    if parts.len() < 3 {
        eprintln!("invalid object format");
        process::exit(1);
    }

    print!("{}", parts[2]);
}

